import { Effect, Data } from "effect";

interface User { readonly id: string; readonly name: string; readonly age: number }

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}
class SchemaError extends Data.TaggedError("SchemaError")<{ readonly reason: string }> {}

const parseUser = (u: unknown): Effect.Effect<User, SchemaError> => {
  if (typeof u !== "object" || u === null) return Effect.fail(new SchemaError({ reason: "not an object" }));
  const r = u as Record<string, unknown>;
  if (typeof r.id !== "string") return Effect.fail(new SchemaError({ reason: "id must be string" }));
  if (typeof r.name !== "string") return Effect.fail(new SchemaError({ reason: "name must be string" }));
  if (typeof r.age !== "number") return Effect.fail(new SchemaError({ reason: "age must be number" }));
  return Effect.succeed({ id: r.id, name: r.name, age: r.age });
};

export const fetchUser = (id: string): Effect.Effect<User, NetworkError | SchemaError> =>
  Effect.gen(function* () {
    const body = yield* Effect.tryPromise({
      try: () => fetch(`/api/users/${id}`).then((r) => r.json() as Promise<unknown>),
      catch: (cause) => new NetworkError({ cause }),
    });
    const user = yield* parseUser(body);
    return user;
  });
