import { Effect, Data } from "effect";

interface Tag { readonly id: number; readonly label: string }

class Net extends Data.TaggedError("Net")<{ readonly cause: unknown }> {}
class Decode extends Data.TaggedError("Decode")<{ readonly at: number; readonly reason: string }> {}

const decodeTag = (u: unknown, i: number): Effect.Effect<Tag, Decode> => {
  if (typeof u !== "object" || u === null) return Effect.fail(new Decode({ at: i, reason: "nil" }));
  const r = u as Record<string, unknown>;
  if (typeof r.id !== "number" || typeof r.label !== "string")
    return Effect.fail(new Decode({ at: i, reason: "shape" }));
  return Effect.succeed({ id: r.id, label: r.label });
};

export const fetchTags = (): Effect.Effect<ReadonlyArray<Tag>, Net | Decode> =>
  Effect.gen(function* () {
    const body = yield* Effect.tryPromise({
      try: () => fetch("/api/tags").then((r) => r.json() as Promise<unknown>),
      catch: (cause) => new Net({ cause }),
    });
    if (!Array.isArray(body)) return yield* Effect.fail(new Decode({ at: -1, reason: "not array" }));
    const out: Tag[] = [];
    for (let i = 0; i < body.length; i++) {
      const t = yield* decodeTag(body[i], i);
      out.push(t);
    }
    return out;
  });
