import { Effect, Layer, Context, Data } from "effect";

class TxError extends Data.TaggedError("TxError")<{ readonly reason: string }> {}

interface Pool { readonly begin: () => Effect.Effect<Handle, TxError>; readonly release: (h: Handle) => Effect.Effect<void> }
interface Handle { readonly _tag: "Handle"; readonly id: number }
const Pool = Context.GenericTag<Pool>("app/Pool");

interface Tx {
  readonly withTx: <A, E>(prog: (h: Handle) => Effect.Effect<A, E>) => Effect.Effect<A, E | TxError>;
}
const Tx = Context.GenericTag<Tx>("app/Tx");

const TxLive: Layer.Layer<Tx, never, Pool> = Layer.effect(
  Tx,
  Effect.gen(function* () {
    const pool = yield* Pool;
    const withTx: Tx["withTx"] = (prog) =>
      Effect.gen(function* () {
        const h = yield* pool.begin();
        const a = yield* prog(h);
        yield* pool.release(h);
        return a;
      });
    return { withTx };
  }),
);

const PoolLive: Layer.Layer<Pool> = Layer.succeed(Pool, {
  begin: () => Effect.succeed({ _tag: "Handle" as const, id: 1 }),
  release: () => Effect.void,
});

export const AppLive: Layer.Layer<Tx> = Layer.provide(TxLive, PoolLive);
