import { Effect, Data } from "effect";

class MissingConfig extends Data.TaggedError("MissingConfig")<{ readonly key: string }> {}
class InvalidConfig extends Data.TaggedError("InvalidConfig")<{ readonly key: string; readonly value: string }> {}

interface AppConfig {
  readonly port: number;
  readonly host: string;
  readonly logLevel: "debug" | "info" | "error";
}

const env = (k: string): Effect.Effect<string, MissingConfig> => {
  const v = process.env[k];
  return v === undefined || v.length === 0
    ? Effect.fail(new MissingConfig({ key: k }))
    : Effect.succeed(v);
};

const parseInt10 = (k: string, v: string): Effect.Effect<number, InvalidConfig> => {
  const n = Number.parseInt(v, 10);
  return Number.isNaN(n) ? Effect.fail(new InvalidConfig({ key: k, value: v })) : Effect.succeed(n);
};

export const loadConfig: Effect.Effect<AppConfig, MissingConfig | InvalidConfig> =
  Effect.gen(function* () {
    const portStr = yield* env("PORT");
    const port = yield* parseInt10("PORT", portStr);
    const host = yield* Effect.orElseSucceed(env("HOST"), () => "localhost");
    const raw = yield* Effect.orElseSucceed(env("LOG_LEVEL"), () => "info");
    const logLevel: AppConfig["logLevel"] =
      raw === "debug" || raw === "info" || raw === "error" ? raw : "info";
    return { port, host, logLevel };
  });
