import { Effect, Data } from "effect";

class MissingUrl extends Data.TaggedError("MissingUrl")<{}> {}
class InvalidUrl extends Data.TaggedError("InvalidUrl")<{ readonly got: string }> {}

interface DbConfig { readonly url: string; readonly host: string; readonly database: string }

const PG_RE = /^postgres:\/\/([^/]+)\/(.+)$/;

export const loadDbConfig: Effect.Effect<DbConfig, MissingUrl | InvalidUrl> =
  Effect.gen(function* () {
    const raw = process.env["DATABASE_URL"];
    if (raw === undefined || raw === "") return yield* Effect.fail(new MissingUrl());
    const m = PG_RE.exec(raw);
    if (m === null) return yield* Effect.fail(new InvalidUrl({ got: raw }));
    const host = m[1];
    const database = m[2];
    if (host === undefined || database === undefined) return yield* Effect.fail(new InvalidUrl({ got: raw }));
    return { url: raw, host, database };
  });
