import { Effect, Schedule, Duration, Data, pipe } from "effect";

class Fail extends Data.TaggedError("Fail")<{}> {}

declare const eff: Effect.Effect<string, Fail>;

// exponential base, cap each delay at 2s, jitter to avoid thundering herd,
// and give up after 6 total attempts via intersect with recurs(5).
const policy = pipe(
  Schedule.exponential(Duration.millis(200)),
  Schedule.either(Schedule.spaced(Duration.seconds(2))),
  Schedule.jittered,
  Schedule.intersect(Schedule.recurs(5)),
);

export const robust: Effect.Effect<string, Fail> = Effect.retry(eff, policy);
