const median = (xs: ReadonlyArray<number>): number => {
  const s = [...xs].sort((a, b) => a - b);
  const mid = Math.floor(s.length / 2);
  const a = s[mid];
  const b = s[mid - 1];
  if (a === undefined) return 0;
  return s.length % 2 === 0 && b !== undefined ? (a + b) / 2 : a;
};

export const medianPrice: Effect.Effect<number, ExErr> = Effect.gen(function* () {
  const prices = yield* Effect.all([ex("binance"), ex("kraken"), ex("coinbase")], {
    concurrency: "unbounded",
  });
  return median(prices);
