import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Adult { readonly age: number; readonly isAdult: true }

const toNumber = (s: string): E.Either<string, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left(`not a number: ${s}`) : E.right(n);
};
const positive = (n: number): E.Either<string, number> =>
  n > 0 ? E.right(n) : E.left("must be positive");
const adult = (n: number): E.Either<string, Adult> =>
  n >= 18 ? E.right({ age: n, isAdult: true }) : E.left("must be >= 18");

export const parseAdultAge = (s: string): E.Either<string, Adult> =>
  pipe(toNumber(s), E.chain(positive), E.chainW(adult));
