import { Effect, Data } from "effect";

class FieldErr extends Data.TaggedError("FieldErr")<{ readonly field: string; readonly reason: string }> {}

interface Form { readonly a: string; readonly b: string; readonly c: string }

const checkA = (s: string) =>
  s.length > 0 ? Effect.succeed(s) : Effect.fail(new FieldErr({ field: "a", reason: "empty" }));
const checkB = (s: string) =>
  s.length > 2 ? Effect.succeed(s) : Effect.fail(new FieldErr({ field: "b", reason: "short" }));
const checkC = (s: string) =>
  /\d/.test(s) ? Effect.succeed(s) : Effect.fail(new FieldErr({ field: "c", reason: "no digit" }));

export const validateForm = (f: Form) =>
  Effect.validateAll(
    [
      ["a", f.a] as const,
      ["b", f.b] as const,
      ["c", f.c] as const,
    ],
    ([k, v]) => (k === "a" ? checkA(v) : k === "b" ? checkB(v) : checkC(v)),
  );
