import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as TE from "fp-ts/TaskEither";

interface Input { readonly email: string; readonly password: string }

const notEmpty = (f: string) => (s: string): E.Either<string, string> =>
  s.length === 0 ? E.left(`${f} empty`) : E.right(s);
const strongPw = (s: string): E.Either<string, string> =>
  s.length >= 8 ? E.right(s) : E.left("password too short");

const syncChecks = (i: Input): E.Either<string, Input> =>
  pipe(
    notEmpty("email")(i.email),
    E.chain(() => strongPw(i.password)),
    E.map(() => i),
  );

declare const isEmailTaken: (email: string) => Promise<boolean>;

const checkUnique = (i: Input): TE.TaskEither<string, Input> =>
  pipe(
    TE.tryCatch(() => isEmailTaken(i.email), (u) => (u instanceof Error ? u.message : String(u))),
    TE.chainW((taken) => (taken ? TE.left("email taken") : TE.right(i))),
  );

export const validateSignup = (i: Input): TE.TaskEither<string, Input> =>
  pipe(TE.fromEither(syncChecks(i)), TE.chainW(checkUnique));
